patch:
Signed-off-by: Dave Müller <dave.mueller@gmx.ch>

--- linux-2.6.34-orig/drivers/gpu/drm/i915/dvo_tfp410.c	2010-04-20 12:55:12.000000000 +0200
+++ linux-2.6.34-patched/drivers/gpu/drm/i915/dvo_tfp410.c	2010-05-22 08:38:39.000000000 +0200
@@ -216,7 +216,7 @@
 	uint8_t ctl2;

 	if (tfp410_readb(dvo, TFP410_CTL_2, &ctl2)) {
-		if (ctl2 & TFP410_CTL_2_HTPLG)
+		if (ctl2 & TFP410_CTL_2_RSEN)
 			ret = connector_status_connected;
 		else
 			ret = connector_status_disconnected;
